  `sc_id` int DEFAULT '0',
  `del` varchar(45) DEFAULT '0',
  `create_date` datetime DEFAULT NULL,
  `update_date` datetime DEFAULT NULL,
  PRIMARY KEY (`ft_id`)
) ENGINE=InnoDB AUTO_INCREMENT=157 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='transaction รับ\n1.1 รับแบบทั่วไป\n  - type = 1\n  - pr_id , prd_id ต้องมีค่า\n  - wc_id , of_id ต้องไม่มีค่า\n1.2 รับแบบหักภาษี ณ ที่จ่าย\n  - type = 1\n  - wc_id , of_id ต้องมีค่า\n  - pr_id , prd_id ต้องไม่มีค่า\n------------------------------------------------\nจ่าย\n - type = -1';
